-- Thittam AI — seed data. AUTO-GENERATED from app/specs/schemes_seed.json
-- (single source of truth). Regenerate with scripts/generate_seed_sql.py.
-- Run AFTER create_tables.sql. Idempotent: upserts on slug.

on conflict (slug) do update set
  name_en = excluded.name_en,
  name_ta = excluded.name_ta,
  level = excluded.level,
  category = excluded.category,
  benefit_en = excluded.benefit_en,
  benefit_ta = excluded.benefit_ta,
  eligibility_rules = excluded.eligibility_rules,
  min_age = excluded.min_age,
  max_age = excluded.max_age,
  gender = excluded.gender,
  states = excluded.states,
  max_income = excluded.max_income,
  social_category = excluded.social_category,
  documents_en = excluded.documents_en,
  documents_ta = excluded.documents_ta,
  how_to_apply_en = excluded.how_to_apply_en,
  how_to_apply_ta = excluded.how_to_apply_ta,
  official_link = excluded.official_link;

select level, count(*) from schemes group by level;
