insert into schemes (slug, name_en, name_ta, level, category, benefit_en, benefit_ta, eligibility_rules, min_age, max_age, gender, states, max_income, social_category, documents_en, documents_ta, how_to_apply_en, how_to_apply_ta, official_link) values
('pm-kisan', 'PM-Kisan Samman Nidhi', 'பிஎம்-கிசான் சம்மான் நிதி', 'central', 'agriculture', 'Rs. 6,000 per year paid directly to farmer families in three installments of Rs. 2,000.', 'விவசாயக் குடும்பங்களுக்கு ஆண்டுக்கு ரூ.6,000, ரூ.2,000 வீதம் மூன்று தவணைகளில் நேரடியாக வழங்கப்படும்.', 'Landholding farmer families (husband, wife, minor children) whose names appear in state land records. Excluded: institutional landholders; families with a member who is/was a government employee (except Group D/multi-tasking staff), a current or former minister/MP/MLA, an income-tax payer in the last assessment year, a professional (doctor, engineer, lawyer, CA, architect) in practice, or a pensioner drawing Rs. 10,000 or more per month.', 18, null, 'all', 'ALL', null, 'all', '["Aadhaar card", "Land ownership records (patta/chitta)", "Bank passbook", "Mobile number"]'::jsonb, '["ஆதார் அட்டை", "நில உரிமை ஆவணங்கள் (பட்டா/சிட்டா)", "வங்கி பாஸ்புக்", "கைபேசி எண்"]'::jsonb, 'Register online at pmkisan.gov.in (Farmers Corner > New Farmer Registration) or through your Village Administrative Officer / Common Service Centre.', 'pmkisan.gov.in-ல் (Farmers Corner > New Farmer Registration) ஆன்லைனில் அல்லது கிராம நிர்வாக அலுவலர் / பொது சேவை மையம் மூலம் பதிவு செய்யலாம்.', 'https://pmkisan.gov.in'),
('pm-fasal-bima', 'Pradhan Mantri Fasal Bima Yojana (Crop Insurance)', 'பிரதம மந்திரி பயிர் காப்பீட்டுத் திட்டம்', 'central', 'agriculture', 'Crop insurance against natural calamities, pests and diseases. Farmer pays only 2% premium for kharif, 1.5% for rabi and 5% for commercial/horticultural crops; the government pays the rest.', 'இயற்கை சீற்றம், பூச்சி, நோய்களால் பயிர் சேதத்துக்கு காப்பீடு. காரீஃப் 2%, ராபி 1.5%, வணிகப் பயிர் 5% மட்டுமே விவசாயி பிரீமியம்; மீதியை அரசு செலுத்தும்.', 'All farmers growing notified crops in notified areas, including sharecroppers and tenant farmers with insurable interest in the crop. Enrolment is voluntary for both loanee and non-loanee farmers. Must enrol before the seasonal cut-off date announced for each crop season.', 18, null, 'all', 'ALL', null, 'all', '["Aadhaar card", "Land records or tenancy/sharecropping agreement", "Bank passbook", "Sowing declaration/crop details"]'::jsonb, '["ஆதார் அட்டை", "நில ஆவணங்கள் அல்லது குத்தகை ஒப்பந்தம்", "வங்கி பாஸ்புக்", "விதைப்பு விவரம்"]'::jsonb, 'Apply at pmfby.gov.in, through your bank, or at a Common Service Centre before the seasonal deadline.', 'pmfby.gov.in-ல், உங்கள் வங்கியில் அல்லது பொது சேவை மையத்தில் பருவ காலக்கெடுவுக்கு முன் விண்ணப்பிக்கவும்.', 'https://pmfby.gov.in'),
('pm-kisan-maandhan', 'PM Kisan Maandhan Yojana (Farmer Pension)', 'பிஎம் கிசான் மான்தன் திட்டம் (விவசாயி ஓய்வூதியம்)', 'central', 'pension', 'Guaranteed monthly pension of Rs. 3,000 after age 60 for small and marginal farmers, with a matching contribution from the government.', 'சிறு, குறு விவசாயிகளுக்கு 60 வயதுக்குப் பிறகு மாதம் ரூ.3,000 உறுதியான ஓய்வூதியம்; அரசு சம பங்களிப்பு செலுத்தும்.', 'Small and marginal farmers owning cultivable land up to 2 hectares, aged 18 to 40 at entry. Monthly contribution of Rs. 55 to Rs. 200 until age 60 depending on entry age. Excluded: farmers covered under NPS, ESIC or EPFO, income-tax payers, and those excluded under PM-Kisan exclusion criteria.', 18, 40, 'all', 'ALL', null, 'all', '["Aadhaar card", "Land records showing up to 2 hectares", "Bank passbook"]'::jsonb, '["ஆதார் அட்டை", "2 ஹெக்டேர் வரை நில ஆவணங்கள்", "வங்கி பாஸ்புக்"]'::jsonb, 'Enrol at your nearest Common Service Centre or online at maandhan.in.', 'அருகிலுள்ள பொது சேவை மையத்தில் அல்லது maandhan.in-ல் பதிவு செய்யலாம்.', 'https://maandhan.in'),
('kisan-credit-card', 'Kisan Credit Card (KCC)', 'கிசான் கடன் அட்டை', 'central', 'agriculture', 'Short-term crop loans up to Rs. 3 lakh at subsidised interest (effective around 4% with prompt repayment), plus coverage for allied activities like dairy and fisheries.', 'ரூ.3 லட்சம் வரை குறைந்த வட்டியில் பயிர்க் கடன் (சரியான திருப்பிச் செலுத்தலில் சுமார் 4%); பால், மீன் வளர்ப்பு போன்றவற்றுக்கும் பொருந்தும்.', 'Farmers (owner cultivators, tenant farmers, sharecroppers, oral lessees) and self-help groups or joint liability groups of farmers, generally aged 18 to 75. Farmers engaged in animal husbandry and fisheries are also eligible for working capital under KCC. A co-borrower is required if the applicant is above 60.', 18, 75, 'all', 'ALL', null, 'all', '["Aadhaar card", "Land records or tenancy proof", "Passport-size photo", "Bank account details"]'::jsonb, '["ஆதார் அட்டை", "நில ஆவணங்கள் அல்லது குத்தகை சான்று", "புகைப்படம்", "வங்கி கணக்கு விவரம்"]'::jsonb, 'Apply at any bank branch or through the bank''s website; a simplified one-page KCC form is available at all banks.', 'எந்த வங்கிக் கிளையிலும் அல்லது வங்கி இணையதளத்திலும் விண்ணப்பிக்கலாம்; எளிய ஒரு பக்க படிவம் உள்ளது.', 'https://www.myscheme.gov.in/schemes/kcc'),
('pmay-gramin', 'PM Awas Yojana - Gramin (Rural Housing)', 'பிரதமர் வீட்டு வசதித் திட்டம் - கிராமப்புறம்', 'central', 'housing', 'Financial assistance of Rs. 1.20 lakh (plain areas) or Rs. 1.30 lakh (hilly/difficult areas) to build a pucca house, plus support for toilets and LPG under converged schemes.', 'நிரந்தர வீடு கட்ட ரூ.1.20 லட்சம் (சமவெளி) / ரூ.1.30 லட்சம் (மலை பகுதி) உதவித்தொகை; கழிப்பறை, எரிவாயு இணைப்பு உதவிகளும் உண்டு.', 'Rural households that are houseless or living in kutcha/dilapidated houses, identified from the SECC 2011 list and Awaas+ survey, and verified by the Gram Sabha. Excluded: households owning a pucca house, motorised vehicle, Kisan Credit Card with limit Rs. 50,000 or more, government employees, or income-tax payers.', 18, null, 'all', 'ALL', null, 'all', '["Aadhaar card", "Job card / MGNREGA number (if any)", "Bank passbook", "Proof of house condition (survey listing)"]'::jsonb, '["ஆதார் அட்டை", "வேலை அட்டை / MGNREGA எண் (இருந்தால்)", "வங்கி பாஸ்புக்", "வீட்டு நிலை சான்று (கணக்கெடுப்பு பட்டியல்)"]'::jsonb, 'Contact your Gram Panchayat or Block Development Office; beneficiary lists come from the Awaas+ survey and are approved by the Gram Sabha.', 'கிராம பஞ்சாயத்து அல்லது வட்டார வளர்ச்சி அலுவலகத்தை அணுகவும்; பயனாளர் பட்டியல் கிராம சபையால் அங்கீகரிக்கப்படும்.', 'https://pmayg.nic.in'),
('pmay-urban', 'PM Awas Yojana - Urban 2.0', 'பிரதமர் வீட்டு வசதித் திட்டம் - நகர்ப்புறம் 2.0', 'central', 'housing', 'Central assistance for urban poor to build or buy a first pucca house, including interest subsidy on home loans and support for beneficiary-led construction.', 'நகர்ப்புற ஏழைகள் முதல் நிரந்தர வீடு கட்ட/வாங்க மத்திய உதவி; வீட்டுக் கடன் வட்டி மானியமும் சுய கட்டுமான உதவியும் உண்டு.', 'Urban families that do not own a pucca house anywhere in India. Income categories: EWS up to Rs. 3 lakh per year, LIG Rs. 3 to 6 lakh, MIG Rs. 6 to 9 lakh. Priority to SC/ST, minorities, widows, persons with disabilities and other vulnerable groups.', 18, null, 'all', 'ALL', 900000, 'all', '["Aadhaar card", "Income certificate/proof", "Bank passbook", "Affidavit of no pucca house ownership", "Land document (for self-construction)"]'::jsonb, '["ஆதார் அட்டை", "வருமான சான்று", "வங்கி பாஸ்புக்", "நிரந்தர வீடு இல்லை என்ற உறுதிமொழி", "நில ஆவணம் (சுய கட்டுமானத்திற்கு)"]'::jsonb, 'Apply through your Urban Local Body (municipality/corporation) or at pmay-urban.gov.in.', 'நகராட்சி/மாநகராட்சி மூலம் அல்லது pmay-urban.gov.in-ல் விண்ணப்பிக்கலாம்.', 'https://pmay-urban.gov.in'),
('ab-pmjay', 'Ayushman Bharat PM-JAY (Health Insurance)', 'ஆயுஷ்மான் பாரத் பிஎம்-ஜே ஏ ஒய் (சுகாதார காப்பீடு)', 'central', 'health', 'Cashless hospital treatment cover of Rs. 5 lakh per family per year at empanelled government and private hospitals across India. Senior citizens aged 70+ are covered regardless of income.', 'ஆண்டுக்கு குடும்பத்திற்கு ரூ.5 லட்சம் வரை பணமில்லா மருத்துவமனை சிகிச்சை. 70 வயதுக்கு மேற்பட்ட மூத்த குடிமக்கள் வருமானம் பாராமல் சேர்க்கப்படுவர்.', 'Families identified under SECC 2011 deprivation and occupational criteria (rural: houseless, landless manual labour, SC/ST households, etc.; urban: listed occupations like ragpickers, street vendors, domestic workers, construction workers). States may include additional families. All citizens aged 70 and above are eligible for a Rs. 5 lakh cover irrespective of income. In Tamil Nadu the scheme runs converged with the state CMCHIS.', null, null, 'all', 'ALL', null, 'all', '["Aadhaar card", "Ration card / family ID", "Mobile number"]'::jsonb, '["ஆதார் அட்டை", "குடும்ப அட்டை", "கைபேசி எண்"]'::jsonb, 'Check eligibility and get your Ayushman card at beneficiary.nha.gov.in, a Common Service Centre, or an empanelled hospital''s Ayushman desk.', 'beneficiary.nha.gov.in-ல், பொது சேவை மையத்தில் அல்லது அங்கீகரிக்கப்பட்ட மருத்துவமனையில் தகுதியை சரிபார்த்து ஆயுஷ்மான் அட்டை பெறலாம்.', 'https://pmjay.gov.in'),
('pm-jan-dhan', 'PM Jan Dhan Yojana (Bank Account)', 'பிரதமர் ஜன் தன் திட்டம் (வங்கி கணக்கு)', 'central', 'social_security', 'Zero-balance bank account with a free RuPay debit card carrying Rs. 2 lakh accident insurance, plus overdraft facility up to Rs. 10,000 for eligible account holders.', 'குறைந்தபட்ச இருப்பு இல்லாத வங்கி கணக்கு; ரூ.2 லட்சம் விபத்து காப்பீட்டுடன் இலவச RuPay அட்டை; தகுதியானவர்களுக்கு ரூ.10,000 வரை ஓவர் டிராஃப்ட்.', 'Any Indian citizen aged 10 or above who does not have a bank account. Overdraft up to Rs. 10,000 is available to one account holder per household (preferably the woman) after satisfactory account operation for 6 months, for ages 18 to 65.', 10, null, 'all', 'ALL', null, 'all', '["Aadhaar card (or other officially valid ID)", "Passport-size photo", "Mobile number"]'::jsonb, '["ஆதார் அட்டை (அல்லது அரசு அங்கீகரித்த அடையாள ஆவணம்)", "புகைப்படம்", "கைபேசி எண்"]'::jsonb, 'Open the account at any bank branch or Bank Mitra (business correspondent) outlet with a one-page form.', 'எந்த வங்கிக் கிளையிலும் அல்லது வங்கி மித்ரா மையத்திலும் ஒரு பக்க படிவத்துடன் கணக்கு தொடங்கலாம்.', 'https://pmjdy.gov.in'),
('pmjjby', 'PM Jeevan Jyoti Bima Yojana (Life Insurance)', 'பிரதமர் ஜீவன் ஜோதி பீமா திட்டம் (ஆயுள் காப்பீடு)', 'central', 'social_security', 'Life insurance cover of Rs. 2 lakh for death due to any reason, at a premium of Rs. 436 per year auto-debited from the bank account.', 'எந்தக் காரணத்தாலும் இறப்பு ஏற்பட்டால் ரூ.2 லட்சம் ஆயுள் காப்பீடு; ஆண்டு பிரீமியம் ரூ.436 வங்கி கணக்கிலிருந்து தானாக பிடித்தம் செய்யப்படும்.', 'Savings bank account holders aged 18 to 50 who consent to auto-debit of the annual premium. Cover continues up to age 55 if premiums are paid. Only one policy per person even with multiple bank accounts.', 18, 50, 'all', 'ALL', null, 'all', '["Bank account with auto-debit consent", "Aadhaar card", "Nominee details"]'::jsonb, '["தானியங்கி பிடித்தம் ஒப்புதலுடன் வங்கி கணக்கு", "ஆதார் அட்டை", "வாரிசுதாரர் விவரம்"]'::jsonb, 'Enrol at your bank branch, via net banking, or through your bank''s mobile app.', 'வங்கிக் கிளை, நெட் பேங்கிங் அல்லது வங்கி செயலி மூலம் சேரலாம்.', 'https://www.jansuraksha.gov.in'),
('pmsby', 'PM Suraksha Bima Yojana (Accident Insurance)', 'பிரதமர் சுரக்ஷா பீமா திட்டம் (விபத்து காப்பீடு)', 'central', 'social_security', 'Accident insurance of Rs. 2 lakh for accidental death or total permanent disability (Rs. 1 lakh for partial disability) at just Rs. 20 per year.', 'விபத்து மரணம் அல்லது முழு நிரந்தர ஊனத்திற்கு ரூ.2 லட்சம் (பகுதி ஊனத்திற்கு ரூ.1 லட்சம்) காப்பீடு; ஆண்டுக்கு ரூ.20 மட்டுமே.', 'Savings bank account holders aged 18 to 70 who consent to auto-debit of the Rs. 20 annual premium. Only one policy per person.', 18, 70, 'all', 'ALL', null, 'all', '["Bank account with auto-debit consent", "Aadhaar card", "Nominee details"]'::jsonb, '["தானியங்கி பிடித்தம் ஒப்புதலுடன் வங்கி கணக்கு", "ஆதார் அட்டை", "வாரிசுதாரர் விவரம்"]'::jsonb, 'Enrol at your bank branch, via net banking, or through your bank''s mobile app.', 'வங்கிக் கிளை, நெட் பேங்கிங் அல்லது வங்கி செயலி மூலம் சேரலாம்.', 'https://www.jansuraksha.gov.in'),
('atal-pension', 'Atal Pension Yojana', 'அடல் ஓய்வூதியத் திட்டம்', 'central', 'pension', 'Guaranteed monthly pension of Rs. 1,000 to Rs. 5,000 after age 60, based on your monthly contribution; spouse continues to receive the pension after the subscriber''s death.', '60 வயதுக்குப் பிறகு மாதம் ரூ.1,000 முதல் ரூ.5,000 வரை உறுதியான ஓய்வூதியம்; சந்தாதாரர் இறப்புக்குப் பின் துணைவருக்கு ஓய்வூதியம் தொடரும்.', 'Indian citizens aged 18 to 40 with a savings bank account. From 1 October 2022, income-tax payers cannot join. Contributions continue until age 60; amount depends on entry age and chosen pension.', 18, 40, 'all', 'ALL', null, 'all', '["Aadhaar card", "Savings bank account", "Mobile number"]'::jsonb, '["ஆதார் அட்டை", "சேமிப்பு வங்கி கணக்கு", "கைபேசி எண்"]'::jsonb, 'Enrol at your bank branch or post office, or via net banking / bank mobile app.', 'வங்கிக் கிளை, அஞ்சலகம் அல்லது நெட் பேங்கிங் மூலம் சேரலாம்.', 'https://www.npscra.nsdl.co.in/scheme-details.php'),
('pm-ujjwala', 'PM Ujjwala Yojana (Free LPG Connection)', 'பிரதமர் உஜ்வலா திட்டம் (இலவச எரிவாயு இணைப்பு)', 'central', 'women_child', 'Free LPG gas connection with first refill and stove free of cost, plus a targeted subsidy on refills for Ujjwala beneficiaries.', 'இலவச சமையல் எரிவாயு இணைப்பு, முதல் சிலிண்டர் மற்றும் அடுப்பு இலவசம்; உஜ்வலா பயனாளிகளுக்கு சிலிண்டர் மானியமும் உண்டு.', 'Adult women from poor households that do not already have an LPG connection. Eligibility via SECC 2011 list, or belonging to SC/ST, PMAY, Antyodaya, forest dwellers, most backward classes, tea garden tribes, islands, or via a 14-point self-declaration of poor status.', 18, null, 'female', 'ALL', null, 'all', '["Aadhaar card", "Ration card", "Bank passbook", "Self-declaration (if not in SECC list)"]'::jsonb, '["ஆதார் அட்டை", "குடும்ப அட்டை", "வங்கி பாஸ்புக்", "சுய உறுதிமொழி (SECC பட்டியலில் இல்லாவிட்டால்)"]'::jsonb, 'Apply at any LPG distributor (Indane/Bharat/HP) or online at pmuy.gov.in.', 'எந்த எரிவாயு விநியோகஸ்தரிடமும் அல்லது pmuy.gov.in-ல் விண்ணப்பிக்கலாம்.', 'https://www.pmuy.gov.in'),
('pm-mudra', 'PM Mudra Yojana (Business Loans)', 'பிரதமர் முத்ரா திட்டம் (தொழில் கடன்)', 'central', 'business', 'Collateral-free business loans for small enterprises: Shishu up to Rs. 50,000, Kishore up to Rs. 5 lakh, Tarun up to Rs. 10 lakh, and Tarun Plus up to Rs. 20 lakh for successful past borrowers.', 'சிறு தொழில்களுக்கு அடமானமில்லா கடன்: சிசு ரூ.50,000 வரை, கிஷோர் ரூ.5 லட்சம் வரை, தருண் ரூ.10 லட்சம் வரை, தருண் பிளஸ் ரூ.20 லட்சம் வரை.', 'Indian citizens aged 18 and above with a plan for a non-farm income-generating micro or small enterprise (manufacturing, trading, services, or allied agriculture activities like poultry and dairy). The applicant should not be a defaulter to any bank.', 18, null, 'all', 'ALL', null, 'all', '["Aadhaar card", "Business plan / quotation", "Proof of business address", "Bank statements", "Passport-size photos"]'::jsonb, '["ஆதார் அட்டை", "தொழில் திட்டம் / விலைப்பட்டியல்", "தொழில் முகவரி சான்று", "வங்கி அறிக்கைகள்", "புகைப்படங்கள்"]'::jsonb, 'Apply at any bank, NBFC or MFI, or online via udyamimitra.in / jansamarth.in.', 'எந்த வங்கி, NBFC, MFI-லும் அல்லது udyamimitra.in / jansamarth.in மூலம் விண்ணப்பிக்கலாம்.', 'https://www.mudra.org.in'),
('stand-up-india', 'Stand-Up India (SC/ST & Women Entrepreneurs)', 'ஸ்டாண்ட்-அப் இந்தியா (SC/ST & பெண் தொழில்முனைவோர்)', 'central', 'business', 'Bank loans between Rs. 10 lakh and Rs. 1 crore for setting up a new (greenfield) enterprise in manufacturing, services, trading or allied agriculture.', 'உற்பத்தி, சேவை, வர்த்தகம் அல்லது வேளாண் சார் துறையில் புதிய தொழில் தொடங்க ரூ.10 லட்சம் முதல் ரூ.1 கோடி வரை வங்கிக் கடன்.', 'SC or ST individuals, or women entrepreneurs of any category, aged 18 and above, setting up a first-time (greenfield) enterprise. For non-individual enterprises, at least 51% shareholding must be held by an SC/ST or woman entrepreneur. Applicant must not be a defaulter to any bank.', 18, null, 'all', 'ALL', null, 'all', '["Aadhaar card", "Caste certificate (for SC/ST applicants)", "Business project report", "Proof of identity and address", "Bank statements"]'::jsonb, '["ஆதார் அட்டை", "சாதி சான்றிதழ் (SC/ST விண்ணப்பதாரர்களுக்கு)", "தொழில் திட்ட அறிக்கை", "அடையாள, முகவரி சான்று", "வங்கி அறிக்கைகள்"]'::jsonb, 'Apply at any scheduled commercial bank branch or online at standupmitra.in.', 'எந்த வணிக வங்கிக் கிளையிலும் அல்லது standupmitra.in-ல் விண்ணப்பிக்கலாம்.', 'https://www.standupmitra.in'),
('pm-vishwakarma', 'PM Vishwakarma (Traditional Artisans)', 'பிஎம் விஸ்வகர்மா (பாரம்பரிய கைவினைஞர்கள்)', 'central', 'business', 'For artisans in 18 traditional trades: Rs. 15,000 toolkit incentive, skill training with Rs. 500/day stipend, and collateral-free loans up to Rs. 3 lakh at 5% interest.', '18 பாரம்பரிய தொழில் கைவினைஞர்களுக்கு: ரூ.15,000 கருவி உதவி, நாள் ஒன்றுக்கு ரூ.500 உதவித்தொகையுடன் பயிற்சி, 5% வட்டியில் ரூ.3 லட்சம் வரை அடமானமில்லா கடன்.', 'Artisans and craftspeople aged 18+ working with hands and tools in one of 18 listed trades (carpenter, blacksmith, goldsmith, potter, cobbler, tailor, mason, barber, garland maker, washerman, fishing net maker, etc.), engaged in the trade on a self-employment basis. Only one member per family; government employees and their family members are not eligible.', 18, null, 'all', 'ALL', null, 'all', '["Aadhaar card", "Ration card", "Bank passbook", "Mobile number"]'::jsonb, '["ஆதார் அட்டை", "குடும்ப அட்டை", "வங்கி பாஸ்புக்", "கைபேசி எண்"]'::jsonb, 'Register at a Common Service Centre with Aadhaar biometric verification; details at pmvishwakarma.gov.in.', 'பொது சேவை மையத்தில் ஆதார் பயோமெட்ரிக் சரிபார்ப்புடன் பதிவு செய்யவும்; விவரங்கள் pmvishwakarma.gov.in.', 'https://pmvishwakarma.gov.in'),
('ignoaps', 'Indira Gandhi National Old Age Pension', 'இந்திரா காந்தி தேசிய முதியோர் ஓய்வூதியம்', 'central', 'pension', 'Monthly pension for BPL senior citizens: Rs. 200 central share for ages 60-79 and Rs. 500 for 80+, topped up by states (in Tamil Nadu the total paid is Rs. 1,200 per month).', 'வறுமைக் கோட்டுக்குக் கீழுள்ள முதியோருக்கு மாத ஓய்வூதியம்: 60-79 வயதுக்கு மத்திய பங்கு ரூ.200, 80+க்கு ரூ.500; மாநில கூடுதல் தொகையுடன் தமிழ்நாட்டில் மொத்தம் ரூ.1,200.', 'Citizens aged 60 or above belonging to a Below Poverty Line (BPL) household as per state BPL lists. No other regular pension from government sources.', 60, null, 'all', 'ALL', null, 'all', '["Aadhaar card", "Age proof", "BPL/ration card", "Bank or post office account"]'::jsonb, '["ஆதார் அட்டை", "வயது சான்று", "BPL/குடும்ப அட்டை", "வங்கி அல்லது அஞ்சலக கணக்கு"]'::jsonb, 'Apply at the Taluk office / Revenue Department or through your Village Administrative Officer; in Tamil Nadu you can also apply via e-Sevai centres.', 'தாலுகா அலுவலகம் / வருவாய்த் துறை அல்லது கிராம நிர்வாக அலுவலர் மூலம்; தமிழ்நாட்டில் இ-சேவை மையங்களிலும் விண்ணப்பிக்கலாம்.', 'https://nsap.nic.in'),
('ignwps', 'Indira Gandhi National Widow Pension', 'இந்திரா காந்தி தேசிய விதவை ஓய்வூதியம்', 'central', 'pension', 'Monthly pension of Rs. 300 (central share) for BPL widows aged 40-79, topped up by states; converts to old age pension at 80.', '40-79 வயது BPL விதவைகளுக்கு மாதம் ரூ.300 (மத்திய பங்கு); மாநில கூடுதல் தொகை உண்டு; 80 வயதில் முதியோர் ஓய்வூதியமாக மாறும்.', 'Widows aged 40 to 79 belonging to a Below Poverty Line household. The pension continues as long as the beneficiary is not remarried and remains BPL.', 40, 79, 'female', 'ALL', null, 'all', '["Aadhaar card", "Husband''s death certificate", "BPL/ration card", "Bank or post office account"]'::jsonb, '["ஆதார் அட்டை", "கணவர் இறப்பு சான்றிதழ்", "BPL/குடும்ப அட்டை", "வங்கி அல்லது அஞ்சலக கணக்கு"]'::jsonb, 'Apply at the Taluk office / Revenue Department with the death certificate; in Tamil Nadu also via e-Sevai centres.', 'இறப்பு சான்றிதழுடன் தாலுகா அலுவலகத்தில்; தமிழ்நாட்டில் இ-சேவை மையங்களிலும் விண்ணப்பிக்கலாம்.', 'https://nsap.nic.in'),
('igndps', 'Indira Gandhi National Disability Pension', 'இந்திரா காந்தி தேசிய மாற்றுத்திறனாளர் ஓய்வூதியம்', 'central', 'pension', 'Monthly pension of Rs. 300 (central share) for BPL persons with severe or multiple disabilities aged 18-79, topped up by states.', 'கடுமையான/பல ஊனமுள்ள 18-79 வயது BPL நபர்களுக்கு மாதம் ரூ.300 (மத்திய பங்கு); மாநில கூடுதல் தொகை உண்டு.', 'Persons aged 18 to 79 from BPL households with severe disability (80% or more) or multiple disabilities, certified by a government medical board.', 18, 79, 'all', 'ALL', null, 'all', '["Aadhaar card", "Disability certificate (80%+)", "BPL/ration card", "Bank or post office account"]'::jsonb, '["ஆதார் அட்டை", "மாற்றுத்திறன் சான்றிதழ் (80%+)", "BPL/குடும்ப அட்டை", "வங்கி அல்லது அஞ்சலக கணக்கு"]'::jsonb, 'Apply at the Taluk office / Revenue Department with the disability certificate; in Tamil Nadu also via e-Sevai centres.', 'மாற்றுத்திறன் சான்றிதழுடன் தாலுகா அலுவலகத்தில்; தமிழ்நாட்டில் இ-சேவை மையங்களிலும் விண்ணப்பிக்கலாம்.', 'https://nsap.nic.in'),
('sukanya-samriddhi', 'Sukanya Samriddhi Yojana (Girl Child Savings)', 'சுகன்யா சம்ரிதி திட்டம் (பெண் குழந்தை சேமிப்பு)', 'central', 'women_child', 'High-interest, tax-free savings account for a girl child; deposits from Rs. 250 to Rs. 1.5 lakh per year, maturing when she turns 21, with partial withdrawal for higher education at 18.', 'பெண் குழந்தைக்கான உயர் வட்டி, வரி இல்லா சேமிப்புக் கணக்கு; ஆண்டுக்கு ரூ.250 முதல் ரூ.1.5 லட்சம் வரை; 21 வயதில் முதிர்வு, 18 வயதில் உயர்கல்விக்கு பகுதி திரும்பப் பெறலாம்.', 'A parent or legal guardian can open the account for a girl child below 10 years of age. Maximum two accounts per family (exception for twins/triplets). The account is in the girl''s name and matures 21 years after opening.', null, null, 'all', 'ALL', null, 'all', '["Girl child''s birth certificate", "Parent/guardian Aadhaar and PAN", "Address proof", "Passport-size photo"]'::jsonb, '["பெண் குழந்தையின் பிறப்பு சான்றிதழ்", "பெற்றோர் ஆதார் மற்றும் PAN", "முகவரி சான்று", "புகைப்படம்"]'::jsonb, 'Open the account at any post office or authorised bank branch.', 'எந்த அஞ்சலகத்திலும் அல்லது அங்கீகரிக்கப்பட்ட வங்கிக் கிளையிலும் கணக்கு தொடங்கலாம்.', 'https://www.indiapost.gov.in/Financial/Pages/Content/Sukanya-Samriddhi-Account.aspx'),
('pmmvy', 'PM Matru Vandana Yojana (Maternity Benefit)', 'பிரதமர் மாத்ரு வந்தனா திட்டம் (மகப்பேறு உதவி)', 'central', 'women_child', 'Cash benefit of Rs. 5,000 for the first child (in instalments) and Rs. 6,000 for the second child if the child is a girl, credited directly to the mother''s bank account.', 'முதல் குழந்தைக்கு ரூ.5,000 (தவணைகளில்), இரண்டாவது குழந்தை பெண்ணாக இருந்தால் ரூ.6,000 நேரடியாக தாயின் வங்கி கணக்கில் வழங்கப்படும்.', 'Pregnant and lactating women aged 19 and above for the first live birth (and second child if a girl). Women in regular government/PSU employment receiving paid maternity leave are excluded. Registration should happen within the timelines from the last menstrual period as notified.', 19, null, 'female', 'ALL', null, 'all', '["Aadhaar card", "MCP (Mother and Child Protection) card", "Bank passbook", "Pregnancy registration at Anganwadi/health centre"]'::jsonb, '["ஆதார் அட்டை", "தாய் சேய் பாதுகாப்பு அட்டை", "வங்கி பாஸ்புக்", "அங்கன்வாடி/சுகாதார நிலையத்தில் கர்ப்ப பதிவு"]'::jsonb, 'Register at your Anganwadi centre or approved health facility, or online at pmmvy.wcd.gov.in.', 'அங்கன்வாடி மையம் அல்லது அங்கீகரிக்கப்பட்ட சுகாதார நிலையத்தில், அல்லது pmmvy.wcd.gov.in-ல் பதிவு செய்யலாம்.', 'https://pmmvy.wcd.gov.in'),
('post-matric-sc', 'Post-Matric Scholarship for SC Students', 'SC மாணவர்களுக்கான மெட்ரிக் பிந்தைய உதவித்தொகை', 'central', 'education', 'Full compulsory fees plus a monthly academic allowance for SC students studying at post-matriculation levels (class 11 to PhD).', 'மெட்ரிக்குப் பிந்தைய (11ஆம் வகுப்பு முதல் PhD வரை) SC மாணவர்களுக்கு முழு கட்டாயக் கட்டணம் மற்றும் மாத கல்வி உதவித்தொகை.', 'Students belonging to Scheduled Castes studying at post-matric level in a recognised institution, with total family income up to Rs. 2.5 lakh per year. Renewal requires promotion to the next class/year.', null, null, 'all', 'ALL', 250000, 'sc_st', '["Caste certificate", "Income certificate", "Previous marksheet", "Aadhaar card", "Bank passbook", "Admission proof/fee receipt"]'::jsonb, '["சாதி சான்றிதழ்", "வருமான சான்றிதழ்", "முந்தைய மதிப்பெண் பட்டியல்", "ஆதார் அட்டை", "வங்கி பாஸ்புக்", "சேர்க்கை சான்று/கட்டண ரசீது"]'::jsonb, 'Apply through the National Scholarship Portal (scholarships.gov.in) or your state''s e-district portal within the notified window each academic year.', 'தேசிய உதவித்தொகை போர்டல் (scholarships.gov.in) அல்லது மாநில இ-சேவை போர்டல் மூலம் அறிவிக்கப்பட்ட காலத்தில் விண்ணப்பிக்கவும்.', 'https://scholarships.gov.in'),
('csss-college', 'Central Sector Scholarship for College Students', 'கல்லூரி மாணவர்களுக்கான மத்திய உதவித்தொகை', 'central', 'education', 'Rs. 12,000 per year for the first three years of undergraduate study and Rs. 20,000 per year at postgraduate level, for meritorious students from low-income families.', 'குறைந்த வருமான குடும்ப திறமையான மாணவர்களுக்கு இளங்கலை முதல் 3 ஆண்டுகள் ஆண்டுக்கு ரூ.12,000, முதுகலை நிலையில் ரூ.20,000.', 'Students above the 80th percentile in their class 12 board exams, pursuing a regular degree course (not correspondence/diploma), with family income up to Rs. 4.5 lakh per year, and not availing any other scholarship. Age below 25 at application.', null, 25, 'all', 'ALL', 450000, 'all', '["Class 12 marksheet", "Income certificate", "Aadhaar card", "Bank passbook", "College admission proof"]'::jsonb, '["12ஆம் வகுப்பு மதிப்பெண் பட்டியல்", "வருமான சான்றிதழ்", "ஆதார் அட்டை", "வங்கி பாஸ்புக்", "கல்லூரி சேர்க்கை சான்று"]'::jsonb, 'Apply on the National Scholarship Portal (scholarships.gov.in) during the annual application window.', 'ஆண்டு விண்ணப்ப காலத்தில் தேசிய உதவித்தொகை போர்டலில் (scholarships.gov.in) விண்ணப்பிக்கவும்.', 'https://scholarships.gov.in'),
('nmmss', 'National Means-cum-Merit Scholarship', 'தேசிய வருமான-திறமை உதவித்தொகை', 'central', 'education', 'Rs. 12,000 per year for meritorious students of classes 9 to 12 in government and government-aided schools, to reduce dropouts after class 8.', 'அரசு/அரசு உதவி பெறும் பள்ளிகளில் 9 முதல் 12ஆம் வகுப்பு வரை திறமையான மாணவர்களுக்கு ஆண்டுக்கு ரூ.12,000.', 'Students who scored at least 55% in class 7 (50% for SC/ST), studying in class 8 when taking the selection test, from families with income up to Rs. 3.5 lakh per year, in government, government-aided or local body schools. Selection is through a state-level exam.', null, null, 'all', 'ALL', 350000, 'all', '["Class 7 marksheet", "Income certificate", "Aadhaar card", "School bonafide certificate", "Bank passbook"]'::jsonb, '["7ஆம் வகுப்பு மதிப்பெண் பட்டியல்", "வருமான சான்றிதழ்", "ஆதார் அட்டை", "பள்ளி சான்றிதழ்", "வங்கி பாஸ்புக்"]'::jsonb, 'Register for the state NMMS selection exam through your school; scholarships are disbursed via the National Scholarship Portal.', 'பள்ளி மூலம் மாநில NMMS தேர்வுக்கு பதிவு செய்யவும்; உதவித்தொகை தேசிய போர்டல் மூலம் வழங்கப்படும்.', 'https://scholarships.gov.in'),
('pmkvy', 'PM Kaushal Vikas Yojana (Free Skill Training)', 'பிரதமர் திறன் மேம்பாட்டுத் திட்டம் (இலவச பயிற்சி)', 'central', 'employment', 'Free short-term skill training and certification in hundreds of job roles, with recognition of prior learning for existing skills.', 'நூற்றுக்கணக்கான தொழில் பிரிவுகளில் இலவச குறுகிய கால திறன் பயிற்சி மற்றும் சான்றிதழ்; ஏற்கனவே உள்ள திறமைகளுக்கு RPL சான்றிதழ்.', 'Indian youth roughly aged 15 to 45 who are unemployed, school/college dropouts, or wish to get certified in a trade. No fee is charged for training under the scheme.', 15, 45, 'all', 'ALL', null, 'all', '["Aadhaar card", "Bank passbook", "Education certificates (if any)"]'::jsonb, '["ஆதார் அட்டை", "வங்கி பாஸ்புக்", "கல்வி சான்றிதழ்கள் (இருந்தால்)"]'::jsonb, 'Find a training centre and courses on the Skill India Digital portal (skillindiadigital.gov.in) and enrol free of cost.', 'Skill India Digital போர்டலில் (skillindiadigital.gov.in) பயிற்சி மையத்தைத் தேடி இலவசமாக சேரலாம்.', 'https://www.skillindiadigital.gov.in'),
('mgnrega', 'MGNREGA (Rural Employment Guarantee)', 'மகாத்மா காந்தி ஊரக வேலை உறுதித் திட்டம்', 'central', 'employment', 'Legal guarantee of 100 days of wage employment per year for every rural household whose adult members volunteer to do unskilled manual work, with wages paid to the bank account.', 'கிராமப்புற குடும்பங்களுக்கு ஆண்டுக்கு 100 நாட்கள் கூலி வேலை சட்ட உத்தரவாதம்; ஊதியம் வங்கி கணக்கில் செலுத்தப்படும்.', 'Any rural household whose adult members (18+) are willing to do unskilled manual work. Registration gives a job card; work must be provided within 15 days of demand, else an unemployment allowance is payable.', 18, null, 'all', 'ALL', null, 'all', '["Aadhaar card", "Passport-size photos of adult members", "Bank/post office account"]'::jsonb, '["ஆதார் அட்டை", "வயது வந்தோரின் புகைப்படங்கள்", "வங்கி/அஞ்சலக கணக்கு"]'::jsonb, 'Apply for a job card at your Gram Panchayat office; then demand work in writing when needed.', 'கிராம பஞ்சாயத்தில் வேலை அட்டைக்கு விண்ணப்பிக்கவும்; தேவைப்படும்போது எழுத்துப்பூர்வமாக வேலை கோரலாம்.', 'https://nrega.nic.in'),
('pudhumai-penn', 'Pudhumai Penn (Moovalur Ramamirtham Scheme)', 'புதுமைப் பெண் (மூவலூர் ராமாமிர்தம் திட்டம்)', 'tn', 'education', 'Rs. 1,000 per month directly to the bank account of girl students who studied classes 6 to 12 in Tamil Nadu government schools and continue to higher education, until course completion.', 'தமிழ்நாடு அரசுப் பள்ளிகளில் 6 முதல் 12ஆம் வகுப்பு வரை படித்து உயர்கல்வி தொடரும் மாணவிகளுக்கு படிப்பு முடியும் வரை மாதம் ரூ.1,000 வங்கி கணக்கில் வழங்கப்படும்.', 'Girl students who studied from class 6 to 12 in Tamil Nadu government schools and enrol in a recognised undergraduate degree, diploma or ITI course. The assistance continues until the course ends, alongside other scholarships. Girls from government-aided schools are covered under the extended phase announced by the state.', 17, null, 'female', 'TN', null, 'all', '["Aadhaar card", "Government school study certificates (classes 6-12)", "Higher education admission proof", "Bank passbook"]'::jsonb, '["ஆதார் அட்டை", "அரசுப் பள்ளி படிப்பு சான்றிதழ்கள் (6-12)", "உயர்கல்வி சேர்க்கை சான்று", "வங்கி பாஸ்புக்"]'::jsonb, 'Apply online at pudhumaipenn.tn.gov.in or through your college after admission.', 'pudhumaipenn.tn.gov.in-ல் அல்லது சேர்க்கைக்குப் பின் உங்கள் கல்லூரி மூலம் விண்ணப்பிக்கலாம்.', 'https://pudhumaipenn.tn.gov.in'),
('kalaignar-magalir-urimai', 'Kalaignar Magalir Urimai Thogai (Women''s Rights Grant)', 'கலைஞர் மகளிர் உரிமைத் தொகை', 'tn', 'women_child', 'Rs. 1,000 per month credited to eligible women heads of families in Tamil Nadu.', 'தமிழ்நாட்டில் தகுதியுள்ள குடும்பத் தலைவிகளுக்கு மாதம் ரூ.1,000 வங்கி கணக்கில் வழங்கப்படும்.', 'Women recognised as family head, aged 21 or above, with family annual income up to Rs. 2.5 lakh. Exclusions include families with more than 5 acres of wetland or 10 acres of dryland, income-tax payers, government employees/pensioners in the family, and households with high electricity consumption (above 3,600 units per year).', 21, null, 'female', 'TN', 250000, 'all', '["Aadhaar card", "Family ration card", "Bank passbook", "Income details"]'::jsonb, '["ஆதார் அட்டை", "குடும்ப அட்டை", "வங்கி பாஸ்புக்", "வருமான விவரம்"]'::jsonb, 'Applications were collected through special camps; check status or apply at kmut.tn.gov.in or your local e-Sevai centre.', 'சிறப்பு முகாம்களில் விண்ணப்பங்கள் பெறப்பட்டன; kmut.tn.gov.in அல்லது இ-சேவை மையத்தில் நிலை அறியலாம்/விண்ணப்பிக்கலாம்.', 'https://www.tn.gov.in/scheme/data_view/98926'),
('cmchis', 'Chief Minister''s Comprehensive Health Insurance (TN)', 'முதலமைச்சரின் விரிவான மருத்துவக் காப்பீட்டுத் திட்டம்', 'tn', 'health', 'Cashless treatment cover up to Rs. 5 lakh per family per year in empanelled government and private hospitals in Tamil Nadu, converged with Ayushman Bharat PM-JAY.', 'தமிழ்நாட்டில் அங்கீகரிக்கப்பட்ட அரசு/தனியார் மருத்துவமனைகளில் ஆண்டுக்கு குடும்பத்திற்கு ரூ.5 லட்சம் வரை பணமில்லா சிகிச்சை.', 'Tamil Nadu resident families with annual family income below Rs. 1.2 lakh (self-certified/verified via ration card family data). Members of families already covered under PM-JAY SECC lists are automatically included. Migrant workers and certain unorganised sector workers are also covered.', null, null, 'all', 'TN', 120000, 'all', '["Aadhaar card", "Family ration card", "Income certificate", "Mobile number"]'::jsonb, '["ஆதார் அட்டை", "குடும்ப அட்டை", "வருமான சான்றிதழ்", "கைபேசி எண்"]'::jsonb, 'Enrol at an empanelled hospital''s CMCHIS/PM-JAY help desk or e-Sevai centre to get the health card.', 'அங்கீகரிக்கப்பட்ட மருத்துவமனையின் உதவி மையம் அல்லது இ-சேவை மையத்தில் பதிவு செய்து அட்டை பெறலாம்.', 'https://www.cmchistn.com'),
('muthulakshmi-maternity', 'Dr. Muthulakshmi Reddy Maternity Benefit (TN)', 'டாக்டர் முத்துலட்சுமி ரெட்டி மகப்பேறு நிதியுதவி', 'tn', 'women_child', 'Rs. 18,000 in instalments plus two nutrition kits for poor pregnant women in Tamil Nadu, for the first two deliveries.', 'தமிழ்நாட்டில் ஏழை கர்ப்பிணிப் பெண்களுக்கு முதல் இரண்டு பிரசவங்களுக்கு தவணைகளில் ரூ.18,000 மற்றும் இரண்டு ஊட்டச்சத்து பொருள் பெட்டகங்கள்.', 'Pregnant women aged 18 and above from poor households in Tamil Nadu, for the first two live deliveries. Registration at the local health facility (PHC/urban health centre) with antenatal check-ups is required; benefit is paid in instalments linked to antenatal care, delivery and immunisation milestones.', 18, null, 'female', 'TN', null, 'all', '["Aadhaar card", "Pregnancy registration (RCH ID) at health centre", "Ration card", "Bank passbook"]'::jsonb, '["ஆதார் அட்டை", "சுகாதார நிலைய கர்ப்ப பதிவு (RCH எண்)", "குடும்ப அட்டை", "வங்கி பாஸ்புக்"]'::jsonb, 'Register your pregnancy with the Village Health Nurse or nearest Primary Health Centre; they process the benefit through the PICME portal.', 'கிராம சுகாதார செவிலியர் அல்லது அருகிலுள்ள ஆரம்ப சுகாதார நிலையத்தில் கர்ப்பத்தை பதிவு செய்யவும்; PICME மூலம் உதவி வழங்கப்படும்.', 'https://picme.tn.gov.in'),
('tn-old-age-pension', 'TN Old Age Pension (Rs. 1,200/month)', 'தமிழ்நாடு முதியோர் ஓய்வூதியம் (மாதம் ரூ.1,200)', 'tn', 'pension', 'Rs. 1,200 per month for destitute elderly persons in Tamil Nadu, paid through bank/post office, with free dhotis/sarees during festivals.', 'தமிழ்நாட்டில் ஆதரவற்ற முதியோருக்கு மாதம் ரூ.1,200; பண்டிகை காலங்களில் இலவச வேட்டி/புடவை.', 'Persons aged 60 or above who are destitute: no regular income or family support, not owning property beyond limits set by the Revenue Department, and not receiving another government pension. Physically verified by the Revenue Inspector before sanction.', 60, null, 'all', 'TN', null, 'all', '["Aadhaar card", "Age proof", "Ration card", "Bank/post office account"]'::jsonb, '["ஆதார் அட்டை", "வயது சான்று", "குடும்ப அட்டை", "வங்கி/அஞ்சலக கணக்கு"]'::jsonb, 'Apply at the Taluk office (Social Security Scheme section) or through an e-Sevai centre.', 'தாலுகா அலுவலகத்தில் (சமூக பாதுகாப்புத் திட்டப் பிரிவு) அல்லது இ-சேவை மையத்தில் விண்ணப்பிக்கலாம்.', 'https://www.tn.gov.in/scheme/data_view/6919'),
('tn-widow-pension', 'TN Destitute Widow Pension (Rs. 1,200/month)', 'தமிழ்நாடு ஆதரவற்ற விதவை ஓய்வூதியம் (மாதம் ரூ.1,200)', 'tn', 'pension', 'Rs. 1,200 per month for destitute widows in Tamil Nadu with no age limit, plus free sarees during festivals.', 'தமிழ்நாட்டில் ஆதரவற்ற விதவைகளுக்கு வயது வரம்பின்றி மாதம் ரூ.1,200; பண்டிகை காலங்களில் இலவச புடவை.', 'Widows aged 18 or above who are destitute — without adequate income or family support to maintain themselves — and not remarried. Verified by the Revenue Department before sanction.', 18, null, 'female', 'TN', null, 'all', '["Aadhaar card", "Husband''s death certificate", "Ration card", "Bank/post office account"]'::jsonb, '["ஆதார் அட்டை", "கணவர் இறப்பு சான்றிதழ்", "குடும்ப அட்டை", "வங்கி/அஞ்சலக கணக்கு"]'::jsonb, 'Apply at the Taluk office with the death certificate, or through an e-Sevai centre.', 'இறப்பு சான்றிதழுடன் தாலுகா அலுவலகத்தில் அல்லது இ-சேவை மையத்தில் விண்ணப்பிக்கலாம்.', 'https://www.tn.gov.in/scheme/data_view/6919'),
('tn-disabled-pension', 'TN Differently Abled Pension', 'தமிழ்நாடு மாற்றுத்திறனாளர் உதவித்தொகை', 'tn', 'pension', 'Monthly maintenance allowance of Rs. 1,500 for persons with severe disabilities in Tamil Nadu (Rs. 1,000 for certain categories), plus other aids and appliances support.', 'தமிழ்நாட்டில் கடுமையான மாற்றுத்திறன் உள்ளவர்களுக்கு மாதம் ரூ.1,500 (சில பிரிவுகளுக்கு ரூ.1,000) பராமரிப்பு உதவித்தொகை; உதவி உபகரணங்களும் வழங்கப்படும்.', 'Tamil Nadu residents with a disability certificate from a government medical board (generally 60% disability or more for maintenance allowance; severe/multiple disabilities for the higher amount), from poor households and not receiving another government pension.', null, null, 'all', 'TN', null, 'all', '["Aadhaar card", "National/state disability ID or certificate", "Ration card", "Bank/post office account"]'::jsonb, '["ஆதார் அட்டை", "மாற்றுத்திறன் அடையாள அட்டை/சான்றிதழ்", "குடும்ப அட்டை", "வங்கி/அஞ்சலக கணக்கு"]'::jsonb, 'Apply at the District Differently Abled Welfare Office or through an e-Sevai centre.', 'மாவட்ட மாற்றுத்திறனாளர் நல அலுவலகம் அல்லது இ-சேவை மையத்தில் விண்ணப்பிக்கலாம்.', 'https://www.tn.gov.in/department/29'),
('tn-first-graduate', 'First Generation Graduate Tuition Fee Concession (TN)', 'முதல் பட்டதாரி கல்விக் கட்டண சலுகை', 'tn', 'education', 'Full tuition fee concession for the entire undergraduate course for Tamil Nadu students who are the first graduates in their family, in government and self-financing colleges (government quota seats).', 'குடும்பத்தில் முதல் பட்டதாரியாக படிக்கும் தமிழ்நாடு மாணவர்களுக்கு இளங்கலை படிப்பு முழுவதும் கல்விக் கட்டணம் முழு விலக்கு (அரசு ஒதுக்கீட்டு இடங்களில்).', 'Students admitted to an undergraduate degree course (arts, science, engineering, etc.) in Tamil Nadu whose parents and elder siblings have no bachelor''s degree — certified by a First Graduate Certificate from the Revenue Department. Annual family income within the limit set for the certificate (commonly Rs. 2.5 lakh). Applies to government quota seats.', 17, null, 'all', 'TN', 250000, 'all', '["First Graduate Certificate (from Taluk office/e-Sevai)", "Income certificate", "Admission proof", "Aadhaar card", "Community certificate"]'::jsonb, '["முதல் பட்டதாரி சான்றிதழ் (தாலுகா/இ-சேவை)", "வருமான சான்றிதழ்", "சேர்க்கை சான்று", "ஆதார் அட்டை", "சாதி சான்றிதழ்"]'::jsonb, 'Get the First Graduate Certificate via e-Sevai (tnesevai.tn.gov.in), then submit it to your college at admission for the fee concession.', 'இ-சேவையில் (tnesevai.tn.gov.in) முதல் பட்டதாரி சான்றிதழ் பெற்று, சேர்க்கையின் போது கல்லூரியில் சமர்ப்பிக்கவும்.', 'https://www.tnesevai.tn.gov.in'),
('naan-mudhalvan', 'Naan Mudhalvan (Skill & Career Platform)', 'நான் முதல்வன் (திறன் மேம்பாட்டுத் திட்டம்)', 'tn', 'employment', 'Free industry-aligned skill courses, career guidance, language and coding training for Tamil Nadu students and youth, online and through colleges.', 'தமிழ்நாடு மாணவர்கள், இளைஞர்களுக்கு இலவச தொழில்சார் திறன் பயிற்சிகள், வழிகாட்டுதல், மொழி மற்றும் கோடிங் பயிற்சி — ஆன்லைன் மற்றும் கல்லூரிகள் வழியாக.', 'School and college students in Tamil Nadu and young job-seekers. College students enrol through their institution; others can register on the portal for open courses.', 15, null, 'all', 'TN', null, 'all', '["Aadhaar card", "Student ID (for college enrolment)", "Mobile number and email"]'::jsonb, '["ஆதார் அட்டை", "மாணவர் அடையாள அட்டை (கல்லூரி சேர்க்கைக்கு)", "கைபேசி எண் மற்றும் மின்னஞ்சல்"]'::jsonb, 'Register at naanmudhalvan.tn.gov.in or through your college''s Naan Mudhalvan coordinator.', 'naanmudhalvan.tn.gov.in-ல் அல்லது கல்லூரி ஒருங்கிணைப்பாளர் மூலம் பதிவு செய்யலாம்.', 'https://naanmudhalvan.tn.gov.in'),
('tn-unemployment-assistance', 'TN Unemployment Assistance Scheme', 'தமிழ்நாடு வேலையில்லா உதவித்தொகை', 'tn', 'employment', 'Monthly cash assistance for registered unemployed youth in Tamil Nadu, tiered by education level (roughly Rs. 300 to Rs. 600 per month).', 'வேலைவாய்ப்பு அலுவலகத்தில் பதிவு செய்த தமிழ்நாடு இளைஞர்களுக்கு கல்வித் தகுதிக்கு ஏற்ப மாதம் சுமார் ரூ.300 முதல் ரூ.600 வரை உதவித்தொகை.', 'Tamil Nadu residents aged 18 to 40 (relaxation for SC/ST and differently abled), registered with the TN employment exchange for at least one year, currently unemployed, with family annual income within the prescribed limit. Assistance amount depends on qualification (below SSLC, SSLC/HSC, degree).', 18, 40, 'all', 'TN', null, 'all', '["Employment exchange registration card", "Education certificates", "Income certificate", "Aadhaar card", "Bank passbook"]'::jsonb, '["வேலைவாய்ப்பு பதிவு அட்டை", "கல்வி சான்றிதழ்கள்", "வருமான சான்றிதழ்", "ஆதார் அட்டை", "வங்கி பாஸ்புக்"]'::jsonb, 'Register/renew at velaivaaippu.gov.in and apply for unemployment assistance through the same portal or district employment office.', 'velaivaaippu.gov.in-ல் பதிவு செய்து அதே போர்டல் அல்லது மாவட்ட வேலைவாய்ப்பு அலுவலகத்தில் விண்ணப்பிக்கலாம்.', 'https://velaivaaippu.gov.in'),
('uyegp', 'Unemployed Youth Employment Generation Programme (TN)', 'வேலையில்லா இளைஞர் வேலைவாய்ப்பு உருவாக்கத் திட்டம்', 'tn', 'business', 'Bank loans with 25% government subsidy (up to Rs. 2.5 lakh subsidy) for unemployed youth to start manufacturing (up to Rs. 10 lakh), service (up to Rs. 5 lakh) or trading (up to Rs. 5 lakh) ventures in Tamil Nadu.', 'தமிழ்நாட்டில் வேலையில்லா இளைஞர்கள் தொழில் தொடங்க 25% அரசு மானியத்துடன் வங்கிக் கடன்: உற்பத்தி ரூ.10 லட்சம், சேவை ரூ.5 லட்சம், வர்த்தகம் ரூ.5 லட்சம் வரை.', 'Tamil Nadu residents aged 18 to 45 (relaxation up to 55 for special categories), minimum 8th standard pass, family annual income up to Rs. 5 lakh. Priority to women, SC/ST, minorities, ex-servicemen and differently abled. The unit must be a new venture in manufacturing, service or trade.', 18, 45, 'all', 'TN', 500000, 'all', '["Aadhaar card", "Education certificate (8th pass)", "Income certificate", "Project report", "Bank passbook", "Community certificate (if applicable)"]'::jsonb, '["ஆதார் அட்டை", "கல்வி சான்றிதழ் (8ஆம் வகுப்பு)", "வருமான சான்றிதழ்", "திட்ட அறிக்கை", "வங்கி பாஸ்புக்", "சாதி சான்றிதழ் (பொருந்தினால்)"]'::jsonb, 'Apply online at msmeonline.tn.gov.in under UYEGP; the District Industries Centre processes applications.', 'msmeonline.tn.gov.in-ல் UYEGP கீழ் விண்ணப்பிக்கவும்; மாவட்ட தொழில் மையம் விண்ணப்பங்களை பரிசீலிக்கும்.', 'https://msmeonline.tn.gov.in'),
('tn-free-house-patta', 'Free House Site Patta Scheme (TN)', 'இலவச வீட்டுமனை பட்டா திட்டம்', 'tn', 'housing', 'Free house site pattas (title deeds) on government land for poor rural families in Tamil Nadu who have no house or house site of their own.', 'சொந்த வீடு/மனை இல்லாத தமிழ்நாடு ஏழை கிராம குடும்பங்களுக்கு அரசு நிலத்தில் இலவச வீட்டுமனை பட்டா வழங்கப்படும்.', 'Poor rural families in Tamil Nadu that own no house or house site anywhere, within income limits set by the Revenue Department. Priority to SC/ST families, widows, differently abled persons and families below the poverty line. Land availability in the village is a practical constraint.', 18, null, 'all', 'TN', null, 'all', '["Aadhaar card", "Ration card", "Income certificate", "No-property affidavit"]'::jsonb, '["ஆதார் அட்டை", "குடும்ப அட்டை", "வருமான சான்றிதழ்", "சொத்து இல்லை உறுதிமொழி"]'::jsonb, 'Apply to the Taluk office (Revenue Department) or through your Village Administrative Officer.', 'தாலுகா அலுவலகம் (வருவாய்த் துறை) அல்லது கிராம நிர்வாக அலுவலர் மூலம் விண்ணப்பிக்கலாம்.', 'https://www.tn.gov.in/department/23'),
('girl-child-protection', 'Sivagami Ammaiyar Girl Child Protection Scheme (TN)', 'சிவகாமி அம்மையார் நினைவு பெண் குழந்தைகள் பாதுகாப்புத் திட்டம்', 'tn', 'women_child', 'Fixed deposit in the girl child''s name for poor families in Tamil Nadu (higher amount for a single girl child, shared for two girls), maturing with annual incentives while she studies.', 'தமிழ்நாட்டில் ஏழை குடும்பங்களின் பெண் குழந்தை பெயரில் வைப்புத்தொகை (ஒரே பெண் குழந்தைக்கு அதிக தொகை, இரு பெண் குழந்தைகளுக்கு பகிர்ந்து); படிக்கும் காலத்தில் ஆண்டு ஊக்கத்தொகையும் உண்டு.', 'Tamil Nadu families with one or two girl children and no male child, where a parent has undergone sterilisation, with family income within the prescribed limit (commonly Rs. 72,000 per year). The deposit is made in the girl''s name and matures when she turns 18, provided she continues her education.', null, null, 'all', 'TN', 72000, 'all', '["Girl child''s birth certificate", "Parents'' Aadhaar", "Income certificate", "Sterilisation certificate", "Ration card"]'::jsonb, '["பெண் குழந்தையின் பிறப்பு சான்றிதழ்", "பெற்றோர் ஆதார்", "வருமான சான்றிதழ்", "குடும்பக் கட்டுப்பாடு சான்றிதழ்", "குடும்ப அட்டை"]'::jsonb, 'Apply at the District Social Welfare Office or through an e-Sevai centre.', 'மாவட்ட சமூக நல அலுவலகம் அல்லது இ-சேவை மையத்தில் விண்ணப்பிக்கலாம்.', 'https://www.tnsocialwelfare.tn.gov.in'),
('tn-marriage-assistance', 'TN Marriage Assistance Schemes', 'தமிழ்நாடு திருமண நிதியுதவித் திட்டங்கள்', 'tn', 'women_child', 'Marriage assistance of Rs. 25,000 (or Rs. 50,000 with a degree/diploma) plus a gold coin for the thirumangalyam, for brides from poor families in Tamil Nadu under various named schemes.', 'தமிழ்நாட்டில் ஏழை குடும்ப மணப்பெண்களுக்கு ரூ.25,000 (பட்டம்/டிப்ளமோ இருந்தால் ரூ.50,000) நிதியுதவி மற்றும் திருமாங்கல்யத்திற்கு தங்க நாணயம்.', 'Brides aged 18 and above from poor Tamil Nadu families, with family annual income up to Rs. 72,000 (higher assistance requires a degree or diploma). Separate named schemes cover daughters of poor widows, orphan girls, inter-caste marriages and remarriage of widows, each with similar income conditions. Apply before the marriage date.', 18, null, 'female', 'TN', 72000, 'all', '["Bride''s Aadhaar and age proof", "Income certificate", "Marriage invitation/registration", "Degree/diploma certificate (for higher amount)", "Bank passbook"]'::jsonb, '["மணப்பெண்ணின் ஆதார் மற்றும் வயது சான்று", "வருமான சான்றிதழ்", "திருமண அழைப்பிதழ்/பதிவு", "பட்டம்/டிப்ளமோ சான்றிதழ் (அதிக தொகைக்கு)", "வங்கி பாஸ்புக்"]'::jsonb, 'Apply through the District Social Welfare Office or e-Sevai centre at least 40 days before the marriage.', 'திருமணத்திற்கு குறைந்தது 40 நாட்களுக்கு முன் மாவட்ட சமூக நல அலுவலகம் அல்லது இ-சேவை மையத்தில் விண்ணப்பிக்கவும்.', 'https://www.tnsocialwelfare.tn.gov.in'),
('vidiyal-payanam', 'Magalir Vidiyal Payanam (Free Bus Travel for Women)', 'மகளிர் விடியல் பயணம் (பெண்களுக்கு இலவச பேருந்து பயணம்)', 'tn', 'women_child', 'Zero-ticket travel for women and transgender persons in ordinary (white board) government town buses across Tamil Nadu.', 'தமிழ்நாடு முழுவதும் சாதாரண (வெள்ளை பலகை) அரசு நகர பேருந்துகளில் பெண்கள் மற்றும் திருநங்கைகளுக்கு இலவச பயணம்.', 'All women and transgender persons travelling in ordinary fare-stage government buses in Tamil Nadu. No registration, card or income condition — a zero-fare ticket is issued on board. Not applicable in express, deluxe or AC services.', null, null, 'female', 'TN', null, 'all', '["None — just board an ordinary government bus"]'::jsonb, '["எதுவும் தேவையில்லை — சாதாரண அரசு பேருந்தில் ஏறினால் போதும்"]'::jsonb, 'No application needed; ask the conductor for the free (zero-fare) ticket.', 'விண்ணப்பம் தேவையில்லை; நடத்துனரிடம் இலவச டிக்கெட் கேட்கவும்.', 'https://www.tn.gov.in/scheme/data_view/98925')
